const rawKey = process.env.MY_ENCRYPTION_KEY;
if (!rawKey || rawKey.length !== 64) {
    throw new Error('Environment variable MY_ENCRYPTION_KEY not set or invalid. Must be a 64-character hex string.');
}
const SECRET_KEY_BUFFER = Buffer.from(rawKey, 'hex');

// Cryptographic parameters
const GCM_IV_LENGTH = 12; // Recommended IV length for AES-GCM
const GCM_TAG_LENGTH = 16; // GCM authentication tag length in bytes

// --- Encryption Function ---
